import openpyxl
import warnings
warnings.filterwarnings('ignore')

# Load the WEO xlsx file
weo_wb = openpyxl.load_workbook('/root/weo_data.xlsx', read_only=True, data_only=True)
ws = weo_wb[weo_wb.sheetnames[0]]

# Read the header row (row 1) - split by tabs
header_cell = ws.cell(row=1, column=1).value
header_parts = header_cell.split('\t')
print('Header parts count:', len(header_parts))

# Find year column indices (starting from index 8)
year_cols = {}  # year -> index
for i, part in enumerate(header_parts):
    if part and part.isdigit() and 1980 <= int(part) <= 2030:
        year_cols[int(part)] = i

print('Year columns found:', sorted(year_cols.keys()))
print('Index for year 2000:', year_cols.get(2000))
print('Index for year 2027:', year_cols.get(2027))

# Find Georgia rows and extract data
georgia_data = {}  # subject -> {year: value}
for row_idx in range(2, 17254):
    cell_val = ws.cell(row=row_idx, column=1).value
    if not cell_val or not isinstance(cell_val, str):
        continue
    parts = cell_val.split('\t')
    if len(parts) > 2 and parts[0] == '915' and parts[1] == 'GEO':
        subject_code = parts[2] if len(parts) > 2 else 'unknown'
        if subject_code in ['NGDP_R', 'NGDP_RPCH']:
            georgia_data[subject_code] = {}
            for year in range(2000, 2028):
                if year in year_cols:
                    idx = year_cols[year]
                    if idx < len(parts):
                        val_str = parts[idx]
                        try:
                            val = float(val_str.replace(',', '')) if val_str and val_str != 'n/a' else None
                        except:
                            val = None
                        georgia_data[subject_code][year] = val
            print(f'Found {subject_code} at row {row_idx}')

# Print the extracted data
for subject, data in georgia_data.items():
    print(f'\n{subject} data for Georgia (2000-2027):')
    for year in sorted(data.keys()):
        print(f'  {year}: {data[year]}')
EOF
